// app/api/admin/hero/route.ts - Admin hero selection
import { NextRequest, NextResponse } from "next/server";
import { withAuth } from "@/lib/auth-middleware";
import { prisma } from "@/lib/db";
import { createSuccessResponse, createErrorResponse } from "@/lib/responses";
import { readHero, writeHero, clearHero } from "@/lib/hero-store";

export async function GET(request: NextRequest) {
  try {
    const { auth, error } = await withAuth(request);
    if (error) return error;
    if (auth?.role !== "ADMIN") {
      return NextResponse.json(createErrorResponse("Forbidden", "Admins only"), {
        status: 403,
      });
    }
    const hero = await readHero();
    return NextResponse.json(createSuccessResponse("Hero media", hero), {
      status: 200,
    });
  } catch (error: any) {
    console.error("Admin get hero error:", error);
    return NextResponse.json(
      createErrorResponse("Failed to load hero", error.message),
      { status: 500 },
    );
  }
}

export async function POST(request: NextRequest) {
  try {
    const { auth, error } = await withAuth(request);
    if (error) return error;
    if (auth?.role !== "ADMIN") {
      return NextResponse.json(createErrorResponse("Forbidden", "Admins only"), {
        status: 403,
      });
    }
    const body = await request.json();
    const { id, type, url, thumbnailUrl } = body || {};
    if (!id || !type || !url) {
      // attempt to read from DB if only id passed
      if (id) {
        const media = await prisma.media.findUnique({ where: { id: Number(id) } });
        if (media) {
          await writeHero({
            id: media.id,
            type: media.type as any,
            url: media.url,
            thumbnailUrl: media.thumbnailUrl || null,
            createdAt: (media as any).createdAt?.toISOString?.() || undefined,
          });
          return NextResponse.json(
            createSuccessResponse("Hero updated", { id: media.id }),
            { status: 200 },
          );
        }
      }
      return NextResponse.json(
        createErrorResponse("Validation failed", "id, type and url are required"),
        { status: 400 },
      );
    }
    await writeHero({ id: Number(id), type, url, thumbnailUrl: thumbnailUrl || null });
    return NextResponse.json(createSuccessResponse("Hero updated", { id }), {
      status: 200,
    });
  } catch (error: any) {
    console.error("Admin set hero error:", error);
    return NextResponse.json(
      createErrorResponse("Failed to set hero", error.message),
      { status: 500 },
    );
  }
}

export async function DELETE(request: NextRequest) {
  try {
    const { auth, error } = await withAuth(request);
    if (error) return error;
    if (auth?.role !== "ADMIN") {
      return NextResponse.json(createErrorResponse("Forbidden", "Admins only"), {
        status: 403,
      });
    }
    await clearHero();
    return NextResponse.json(createSuccessResponse("Hero cleared", {}), {
      status: 200,
    });
  } catch (error: any) {
    console.error("Admin clear hero error:", error);
    return NextResponse.json(
      createErrorResponse("Failed to clear hero", error.message),
      { status: 500 },
    );
  }
}

